const gdLineData = {{node:search_node_JWZYxvf2.data.data}}

const gdIDs = [...new Set(gdLineData.map(item => item.goods_delivery_id))];

return { gd_ids: gdIDs };

const pickingSetup = {{node:get_node_DPguoUvG.data.data}} || {};
const allowFullPicking = pickingSetup.allow_full_picking === 1;

let gdLineData = {{node:search_node_JWZYxvf2.data.data}} || [];
const gdData = {{node:search_node_rxIt49E4.data.data}} || [];

const gdById = new Map();
for (const gd of gdData) {
  gdById.set(gd.id, gd);
}

// When allow_full_picking is ON, rewrite each line's temp_qty_data to the
// actually-remaining allocation by subtracting picked_temp_qty_data per
// (location, batch, HU). Mirrors GDconvertToPicking's subtractPickedFromTemp.
const subtractPickedFromTemp = (lineItem) => {
  let tempArr = [];
  try {
    tempArr = lineItem.temp_qty_data ? JSON.parse(lineItem.temp_qty_data) : [];
  } catch (e) { tempArr = []; }

  let pickedArr = [];
  try {
    pickedArr = lineItem.picked_temp_qty_data
      ? JSON.parse(lineItem.picked_temp_qty_data)
      : [];
  } catch (e) { pickedArr = []; }

  if (!Array.isArray(tempArr) || tempArr.length === 0) return tempArr;
  if (!Array.isArray(pickedArr) || pickedArr.length === 0) return tempArr;

  const keyOf = (e) =>
    (e.location_id || 'no-loc') + '_' +
    (e.batch_id || 'no-batch') + '_' +
    (e.handling_unit_id || 'no-hu');

  const pickedByKey = new Map();
  for (const p of pickedArr) {
    const k = keyOf(p);
    pickedByKey.set(k, (pickedByKey.get(k) || 0) + parseFloat(p.gd_quantity || 0));
  }

  const remaining = [];
  for (const t of tempArr) {
    const used = pickedByKey.get(keyOf(t)) || 0;
    const rem = parseFloat(t.gd_quantity || 0) - used;
    if (rem > 0) {
      remaining.push({ ...t, gd_quantity: rem });
    }
  }
  return remaining;
};

// Filter eligible lines based on flag.
const eligibleLines = gdLineData.filter((line) => {
  if (allowFullPicking) {
    const remaining = (line.gd_qty || 0) - (line.picked_qty || 0);
    return (
      remaining > 0 &&
      line.picking_status !== 'Completed' &&
      line.picking_status !== 'Cancelled'
    );
  }
  return line.picking_status === 'Not Created';
});

const mapLineItem = (lineItem, parentGd) => {
  const tablePickingItems = [];
  const pickingItemGroups = new Map();

  if (!lineItem.material_id) return tablePickingItems;

  let tempData;
  if (allowFullPicking) {
    tempData = subtractPickedFromTemp(lineItem);
  } else {
    try {
      tempData = lineItem.temp_qty_data ? JSON.parse(lineItem.temp_qty_data) : [];
    } catch (e) { tempData = []; }
  }
  if (!Array.isArray(tempData) || tempData.length === 0) return tablePickingItems;

  for (const tempItem of tempData) {
    const materialId = String(tempItem.material_id || lineItem.material_id);
    const groupKey = `${lineItem.id}_${materialId}_${
      tempItem.batch_id || "no-batch"
    }_${tempItem.location_id}_${tempItem.handling_unit_id || "no-hu"}`;

    if (!pickingItemGroups.has(groupKey)) {
      pickingItemGroups.set(groupKey, {
        item_code: String(materialId),
        item_name: lineItem.material_name,
        item_desc: lineItem.gd_material_desc || "",
        batch_no: tempItem.batch_id ? String(tempItem.batch_id) : null,
        qty_to_pick: 0,
        item_uom: String(lineItem.good_delivery_uom_id || ""),
        source_bin: String(tempItem.location_id),
        pending_process_qty: 0,
        line_status: "Open",
        so_no: lineItem.line_so_no,
        gd_no: parentGd ? parentGd.delivery_no : "",
        so_id: String(lineItem.line_so_id || ""),
        so_line_id: String(lineItem.so_line_item_id || ""),
        gd_id: parentGd ? String(parentGd.id) : "",
        gd_line_id: String(lineItem.id),
        serial_numbers: [],
        is_serialized_item: 0,
        handling_unit_id: tempItem.handling_unit_id ? String(tempItem.handling_unit_id) : null,
      });
    }

    const group = pickingItemGroups.get(groupKey);
    group.qty_to_pick += parseFloat(tempItem.gd_quantity || 0);
    group.pending_process_qty += parseFloat(tempItem.gd_quantity || 0);

    if (tempItem.serial_number) {
      group.serial_numbers.push(String(tempItem.serial_number));
      group.is_serialized_item = 1;
    }
  }

  for (const group of pickingItemGroups.values()) {
    if (group.serial_numbers.length > 0) {
      group.serial_numbers = group.serial_numbers.join(", ");
    } else {
      delete group.serial_numbers;
    }
    tablePickingItems.push({ ...group });
  }

  return tablePickingItems;
};

let pickingLineItemPromises = [];
for (const line of eligibleLines) {
  const parentGd = gdById.get(line.goods_delivery_id?.id || line.goods_delivery_id);
  const items = mapLineItem(line, parentGd);
  pickingLineItemPromises.push(...items);
}

// Cluster HU rows within each gd_line_id and insert header rows above each
// consecutive HU run (matches GDconvertToPicking's withHeaders logic).
pickingLineItemPromises.sort((a, b) => {
  if (a.gd_line_id !== b.gd_line_id) return 0;
  const aHU = a.handling_unit_id || "";
  const bHU = b.handling_unit_id || "";
  if (aHU === bHU) return 0;
  return aHU < bHU ? -1 : 1;
});

const withHeaders = [];
let lastHuId = null;
for (const row of pickingLineItemPromises) {
  const huId = row.handling_unit_id;
  if (huId && huId !== lastHuId) {
    withHeaders.push({
      row_type: "header",
      handling_unit_id: huId,
      hu_select: 0,
    });
    lastHuId = huId;
  } else if (!huId) {
    lastHuId = null;
  }
  withHeaders.push({ ...row, row_type: "item" });
}
pickingLineItemPromises = withHeaders;

const gdIDs = [
  ...new Set(
    eligibleLines
      .map((l) => String(l.goods_delivery_id?.id || l.goods_delivery_id || ""))
      .filter(Boolean)
  ),
];
const gdNos = [
  ...new Set(
    eligibleLines
      .map((l) => {
        const gd = gdById.get(l.goods_delivery_id?.id || l.goods_delivery_id);
        return gd ? gd.delivery_no : null;
      })
      .filter(Boolean)
  ),
].join(", ");
const soNos = [
  ...new Set(eligibleLines.map((l) => l.line_so_no).filter(Boolean)),
].join(", ");
const gdCustomers = [
  ...new Set(eligibleLines.map((l) => String(l.customer_id?.id || l.customer_id || "")).filter(Boolean)),
];
const plantID = {{workflowparams:plant_id}};

return {
  so_no: soNos,
  delivery_no: gdNos,
  gd_no: gdIDs,
  ref_doc_type: "Goods Delivery",
  table_picking_items: pickingLineItemPromises,
  customer_id: gdCustomers,
  plant_id: plantID,
};
